class DSU {
    vector<int> parent;
    vector<int> rank;
    int count;
public:
    DSU(int n) {
        parent.resize(n);
        rank.resize(n);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
            rank[i] = 0;
        }
        count = n;
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    bool union_(int x, int y) {
        int xroot = find(x);
        int yroot = find(y);
        if (xroot == yroot) return false;
        if (rank[xroot] < rank[yroot]) {
            parent[xroot] = yroot;
        } else {
            parent[yroot] = xroot;
            if (rank[xroot] == rank[yroot]) {
                rank[xroot]++;
            }
        }
        count--;
        return true;
    }
    int get_count() const {
        return count;
    }
};

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    if (edges.empty()) {
        return 0;
    }

    long long max_time = 0;
    for (auto& e : edges) {
        max_time = max(max_time, e[2]);
    }

    long long low = 0, high = max_time;
    long long answer = max_time;

    while (low <= high) {
        long long mid = (low + high) / 2;
        DSU dsu(n);
        for (auto& e : edges) {
            if (e[2] > mid) {
                dsu.union_(e[0], e[1]);
            }
        }
        if (dsu.get_count() >= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
